interface.definition:
a!localVariables(
  local!prisonId: property(
    #"_a-0000ee0e-a4b3-8000-9bf2-011c48011c48_1527068"(user: loggedInUser()),
    "data",
    null
  )[#"urn:appian:record-field:v1:3854eb39-6a61-48cd-82b6-e4645b2900fe/cce64326-22d6-4079-a39f-cb5e0292e234"],
  #"SYSTEM_SYSRULES_headerContentLayout"(
    header: #"SYSTEM_SYSRULES_billboardLayout_v1"(
      backgroundMedia: #"SYSTEM_SYSRULES_documentImage"(
        document: #"_a-0000ed02-f63d-8000-9bea-011c48011c48_1069318"
      ),
      backgroundColor: #"_a-0000ed02-f63d-8000-9bea-011c48011c48_1068602",
      height: "EXTRA_SHORT",
      marginBelow: "NONE",
      overlay: #"SYSTEM_SYSRULES_fullOverlay"(
        contents: {
          #"SYSTEM_SYSRULES_richTextDisplayField"(),
          #"SYSTEM_SYSRULES_sideBySideLayout"(
            items: {
              #"SYSTEM_SYSRULES_sideBySideItem"(
                item: #"SYSTEM_SYSRULES_richTextDisplayField"(
                  labelPosition: "COLLAPSED",
                  value: {
                    #"SYSTEM_SYSRULES_richTextItem_v1"(
                      text: {
                        #"urn:appian:translation-string:v1:3c2f1b79-f08c-47dd-a565-3fe566a9f5be"
                      },
                      size: "LARGE"
                    )
                  }
                )
              ),
              #"SYSTEM_SYSRULES_sideBySideItem"(
                item: #"SYSTEM_SYSRULES_richTextDisplayField"(labelPosition: "COLLAPSED", value: {})
              ),
              #"SYSTEM_SYSRULES_sideBySideItem"(
                item: #"SYSTEM_SYSRULES_richTextDisplayField"(
                  labelPosition: "COLLAPSED",
                  value: a!localVariables(
                    local!now: a!refreshVariable(value: now(), refreshInterval: 1),
                    #"SYSTEM_SYSRULES_richTextItem_v1"(
                      text: text(local!now, "dddd, dd. mmmm hh:mm"),
                      size: "LARGE"
                    )
                  )
                ),
                width: "MINIMIZE"
              ),
              #"SYSTEM_SYSRULES_sideBySideItem"(
                item: #"SYSTEM_SYSRULES_imageField_v1"(
                  labelPosition: "COLLAPSED",
                  images: #"SYSTEM_SYSRULES_documentImage"(
                    document: #"_a-0000ed87-2144-8000-9bee-011c48011c48_1076413"
                  ),
                  size: "TINY",
                  align: "END"
                ),
                width: "MINIMIZE"
              )
            }
          )
        },
        style: "SEMI_DARK"
      )
    ),
    isHeaderFixed: true,
    contents: {
      #"SYSTEM_SYSRULES_cardLayout"(
        showBorder: false,
        showShadow: true,
        shape: "SEMI_ROUNDED",
        padding: "LESS",
        contents: {
          #"SYSTEM_SYSRULES_gridField_v3"(
            labelPosition: "COLLAPSED",
            data: #"SYSTEM_SYSRULES_recordData"(
              recordtype: #"urn:appian:record-type:v1:b9f2b8a1-aa3c-420e-9856-a362e5c58683",
              filters: if(
                #"urn:appian:function:v1:a:isusermemberofgroup?okey=a!isUserMemberOfGroup"(
                  username: loggedInUser(),
                  groups: #"_a-0000ed87-2144-8000-9bee-011c48011c48_1418982"
                ),
                {},
                #"SYSTEM_SYSRULES_queryFilter"(
                  applyWhen: a!isNotNullOrEmpty(local!prisonId),
                  field: #"urn:appian:record-field:v1:b9f2b8a1-aa3c-420e-9856-a362e5c58683/fc3d08af-a253-434c-b9c7-16ff16d2c803",
                  operator: "in",
                  value: local!prisonId
                )
              ),

            ),
            columns: #"_a-0000ee0e-a4b3-8000-9bf2-011c48011c48_1533765"(),
            pageSize: 20,
            refreshAfter: "RECORD_ACTION",

          )
        }
      )
    }
  )
)
